INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('HR管培生 - 北京（校招）', '互联网 / IT', '北京', '民营企业', 10000, 15000, '1. 熟练使用Office办公软件；2. 具备基础的HR项目执行与落地能力', '1. 目标导向、强沟通、强逻辑、强抗压；2. 学习能力强，具备良好的业务理解能力；3. 具备优秀的团队协作能力与执行力', 1, '友好', '1. 参与公司HRBP项目，有效推动招聘、培训、薪酬绩效等项目在公司落地；2. 贴近公司的业务，理解组织现状，做好员工异动管理工作；3. 推动文化落地，延续良好组织氛围，提升组织效能', '招聘全流程执行、员工关系支持、OD 组织发展支持、薪酬绩效支持', '本科及以上', '无强制专业限制', '应届生/毕业1年内，熟悉招聘、绩效、人才盘点、员工关系、目标管理中2-3个模块，有相关落地执行经验', '应届生校招', '有HR相关实习经验者优先', '10k-15k/月', '45304', '46112', 'https://www.shixiseng.com/intern/inn_kyejgc4qpjp?pcm=pc_SearchList', '人力管培生类', '甲方（企业自有 HR 岗）'), ('人力资源管培生 - 上海（校招）', '互联网 / IT', '上海', '民营企业', 5000, 10000, '1. 熟练使用Office办公软件；2. 具备基础的HR全模块认知与执行能力', '1. 优秀的专业基础和研究能力，良好的个人形象和沟通能力；2. 良好的时间管理能力和项目进度管理能力；3. 学习能力强，具备良好的逻辑思维与抗压能力', 1, '友好', '1. 招聘管理：负责技术团队研发岗位招聘、销售团队岗位招聘交付，包括但不限于校招渠道开拓，高管人才招聘，优化招聘策略，提升效率；2. 培训管理：通过研究建立培训体系和培训制度，推动培训流程体系，赋能业务；3. 绩效管理：完善绩效考核体系，推动绩效开展实施，提升公司绩效水平；4. 薪酬管理：根据公司业务发展，建立薪酬福利体系，评估计算薪酬体系合理性，有效提升投入产出比；5. 员工关系：负责员工满意度管理及法律风险管理', '招聘全流程执行、渠道拓展与运营、OD 组织发展支持、薪酬绩效支持、员工关系支持', '本科及以上', '人力资源管理专业或工商管理专业', '2026届应届生', '应届生校招', '有HR相关实习经验者优先', '薪资面议', '46112', NULL, 'https://www.shixiseng.com/intern/inn_ymk4gu9wjvei?pcm=pc_SearchList', '人力管培生类', '甲方（企业自有 HR 岗）'), ('HRBP助理实习生 - 深圳（实习）', '医疗健康 / 生物', '深圳', '民营企业', 80000, 100, '1. 熟练运用基础办公软件；2. 具备基础的人事行政事务执行能力', '1. 执行力强、亲和力较强、办事靠谱；2. 工作认真负责，细心严谨；3. 具备良好的沟通协调能力', 1, '极度友好', '协助HRBP完成乐华华南区的部分人事/行政工作，包括招聘、入离职手续办理、文化活动组织、办公环境的维护、费用报销等', '招聘全流程执行、简历筛选与面试、员工关系支持', '本科及以上', '人力资源/行政管理专业优先', '本科在读，每周可实习2-3天，可实习3个月，接受大一、大二在校生', '日常实习', '有HR相关实习经验者优先', '80-100元/天', '45053', '46112', 'https://www.shixiseng.com/intern/inn_kjtp7jxzbeu?pcm=pc_SearchList', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HRBP助理实习生 - 深圳（实习）', '制造', '深圳', '外资企业', 150, 200, '1. 具备较好的英语读写能力，工作中会用到口语与写作；2. 熟练使用Office办公软件；3. 具备基础的招聘流程执行能力', '1. 有良好的沟通表达、协调和关注细节能力；2. 学习能力强，积极主动，细心负责；3. 具备良好的团队协作能力', 1, '极度友好', '1. 维护、拓展公司招聘渠道，更新招聘信息；2. 根据JD筛选、推荐简历，协调面试官、候选人沟通；3. 负责跟进面试安排和面试反馈等整体招聘流程；4. 协助培训及企业文化项目的实施；5. 完成上级安排的其他HR相关工作', '招聘全流程执行、渠道拓展与运营、简历筛选与面试、OD 组织发展支持', '本科及以上', '无强制专业限制', '本科或研究生在读，大三/大四/研究生学生优先，可实习3-6个月，每周至少工作3天+', '日常实习', '有半导体/芯片行业、HR相关实习经验者优先', '150-200元/天', '45490', '46112', 'https://www.shixiseng.com/intern/inn_11mgfl75w8t3x?pcm=pc_SearchList', 'HRBP类', '甲方（企业自有 HR 岗）'), ('HRBP助理实习生 - 上海（实习）', '人力资源服务 / 咨询', '上海', '国企 / 央企', 150, 200, '1. 英语熟练，通过英语六级，具备优秀的书面及口头沟通能力；2. 熟练掌握数据分析，精通Excel操作；3. 具备基础的调研分析与报告撰写能力', '1. 具备良好的沟通表达能力和执行力，做事认真细致，有责任心；2. 具备良好的团队协作意识；3. 学习能力强，逻辑思维清晰', 1, '友好', '1. 协助HRBP，参与人才发展、学习发展及企业文化建设项目的设计与落地执行；2. 支持内部沟通及相关活动开展；3. 运用分析工具，对内部人员与组织相关数据、指标进行调研分析，并跟进后续行动计划；4. 研究人力资源领域最佳实践，为持续优化提供改进建议', 'OD 组织发展支持、招聘数据分析、员工关系支持', '不限', '人力资源管理专业优先，有相关实习优先', '可实习6个月，每周到岗3天', '日常实习', '掌握Power BI及AI工具者优先', '150-200元/天', '46112', '46204', 'https://www.shixiseng.com/intern/inn_sccjmk8qcluh?pcm=pc_SearchList', 'HRBP类', '乙方（人力资源服务商 / 猎头 / 咨询公司）');